type ButtonTextProps = {
  className?: string;
  state?: "Focus" | "Default" | "Hover" | "State4";
};

export default function ButtonText({ className, state = "Default" }: ButtonTextProps) {
  const isFocus = state === "Focus";
  const isHover = state === "Hover";
  const isState4 = state === "State4";
  return (
    <div className={className || `${String.raw`content-stretch flex gap-[var(--spacing\/2,8px)] h-[var(--height\/h-8,32px)] items-center justify-center pl-[var(--spacing\/3,12px)] pr-[var(--spacing\/4,16px)] py-[var(--spacing\/1,4px)] relative rounded-[var(--border-radius\/rounded-md,8px)] `}${isState4 ? "" : isFocus ? String.raw`bg-[var(--brand\/blue-monkey\/50,#ddeaff)] border border-[var(--brand\/blue-monkey\/500,#2862cb)] border-solid` : isHover ? String.raw`bg-[var(--brand\/blue-monkey\/50,#ddeaff)]` : String.raw`bg-[var(--tailwind-colors\/base\/transparent,rgba(255,255,255,0))]`}`}>
      <div className="content-stretch flex flex-col items-center justify-center relative shrink-0 size-[16px]">
        <div className={`flex flex-col font-["Font_Awesome_7_Free:Solid",sans-serif] justify-end leading-[0] not-italic relative shrink-0 text-[15px] w-full ${isState4 ? String.raw`text-[color:var(--iconitify\/ic-disable,#cbd5e1)]` : String.raw`text-[color:var(--iconitify\/ic-primary,#143166)] text-center`}`}>
          <p className="leading-[1.4]">circle</p>
        </div>
      </div>
      <div className={`${String.raw`flex flex-col justify-center leading-[0] relative shrink-0 text-[length:var(--text\/sm\/font-size,14px)] whitespace-nowrap `}${isState4 ? String.raw`font-["Noto_Sans_JP:Regular",sans-serif] font-normal text-[color:var(--text\/text-disable,#cbd5e1)]` : ["Hover", "Focus"].includes(state) ? String.raw`font-["Noto_Sans_JP:Bold",sans-serif] font-bold text-[color:var(--text\/text-brand,#2862cb)]` : String.raw`font-["Noto_Sans_JP:Regular",sans-serif] font-normal text-[color:var(--text\/text-primary,#0d2144)]`}`}>
        <p className="leading-none">ボタン</p>
      </div>
    </div>
  );
}
